import java.util.*;

public class Solution {
    private static List<Integer> validMs;
    private static int m;
    private static String s;
    private static Long[][][] memo;

    public static long solve(long n, long k) {
        if (k == 0) {
            return n >= 1 ? 1 : 0;
        }

        int maxBits = 60;
        int[] depth = new int[maxBits + 2];
        depth[1] = 0;
        for (int i = 2; i <= maxBits; i++) {
            depth[i] = depth[Integer.bitCount(i)] + 1;
        }

        long target = k - 1;
        validMs = new ArrayList<>();
        for (int i = 1; i <= maxBits; i++) {
            if (depth[i] == target) {
                validMs.add(i);
            }
        }
        if (validMs.isEmpty()) {
            return 0;
        }

        long total = 0;
        s = Long.toBinaryString(n);
        for (int currentM : validMs) {
            m = currentM;
            memo = new Long[s.length()][m + 1][2];
            total += dp(0, 0, 1);
        }
        return total;
    }

    private static long dp(int pos, int cnt, int tight) {
        if (pos == s.length()) {
            return cnt == m ? 1 : 0;
        }
        if (memo[pos][cnt][tight] != null) {
            return memo[pos][cnt][tight];
        }
        int limit = tight == 1 ? s.charAt(pos) - '0' : 1;
        long res = 0;
        for (int d = 0; d <= limit; d++) {
            int newTight = (tight == 1 && d == limit) ? 1 : 0;
            int newCnt = cnt + (d == 1 ? 1 : 0);
            if (newCnt > m) {
                continue;
            }
            res += dp(pos + 1, newCnt, newTight);
        }
        memo[pos][cnt][tight] = res;
        return res;
    }
}
