    public static long solve(long n, long k) {
        if (k == 0) {
            return n >= 1 ? 1 : 0;
        }
        precomputeDepth();
        int target = (int) (k - 1);
        List<Integer> validMs = new ArrayList<>();
        for (int m = 1; m <= 60; m++) {
            if (depth[m] == target) {
                validMs.add(m);
            }
        }
        if (validMs.isEmpty()) {
            return 0;
        }
        long total = 0;
        String s = Long.toBinaryString(n);
        for (int m : validMs) {
            total += countNumbersWithSetBits(s, m);
        }
        return total;
    }

    private static void precomputeDepth() {
        depth = new int[61];
        depth[1] = 0;
        for (int i = 2; i <= 60; i++) {
            depth[i] = depth[Integer.bitCount(i)] + 1;
        }
    }

    private static long countNumbersWithSetBits(String s, int m) {
        int len = s.length();
        long[][][] dp = new long[len][m + 1][2];
        for (long[][] arr1 : dp) {
            for (long[] arr2 : arr1) {
                Arrays.fill(arr2, -1);
            }
        }
        return dfs(s, 0, 0, true, m, dp);
    }

    private static long dfs(String s, int pos, int cnt, boolean tight, int m, long[][][] dp) {
        if (pos == s.length()) {
            return cnt == m ? 1 : 0;
        }
        int tightInt = tight ? 1 : 0;
        if (dp[pos][cnt][tightInt] != -1) {
            return dp[pos][cnt][tightInt];
        }
        int limit = tight ? (s.charAt(pos) - '0') : 1;
        long res = 0;
        for (int d = 0; d <= limit; d++) {
            boolean newTight = tight && (d == limit);
            int newCnt = cnt + (d == 1 ? 1 : 0);
            if (newCnt > m) {
                continue;
            }
            res += dfs(s, pos + 1, newCnt, newTight, m, dp);
        }
        dp[pos][cnt][tightInt] = res;
        return res;
    }
}
